PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?finalBook ?finalBookLabel WHERE {
  wd:Q523076 wdt:P156 ?sequel1 .
  ?sequel1 wdt:P156 ?finalBook .
  OPTIONAL {
    ?finalBook rdfs:label ?finalBookLabel .
    FILTER(lang(?finalBookLabel) = "en")
  }
}

